import{_ as t,o,c as d,ag as r}from"./chunks/framework.Nx1zvZTu.js";const u=JSON.parse('{"title":"Authoring for agents","description":"","frontmatter":{},"headers":[],"relativePath":"mcp/authoring.md","filePath":"mcp/authoring.md"}'),a={name:"mcp/authoring.md"};function c(n,e,i,s,l,h){return o(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="authoring-for-agents" tabindex="-1">Authoring for agents <a class="header-anchor" href="#authoring-for-agents" aria-label="Permalink to &quot;Authoring for agents&quot;">​</a></h1><p>The MCP exposes machinable as curated, task-shaped tools (not one per endpoint), readable resources (the spec the agent writes against), and prompts (canned workflows). The leverage is in the resources, since a handful of good, current-API examples makes first-try code correct.</p><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h2><p><strong>Authoring</strong></p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>list_modules</code></td><td>the project&#39;s interface modules (module, kind, doc, is-widget)</td></tr><tr><td><code>get_module(module)</code></td><td>resolved schema: config fields + the <code>~version</code> vocabulary (signatures + docs)</td></tr><tr><td><code>resolve_config(target, version)</code></td><td>dry-run a compact version → resolved config + CLI, no materialize</td></tr><tr><td><code>read_source</code> / <code>write_source</code> / <code>move_source</code> / <code>delete_source</code></td><td>edit project files; <code>write_source</code> re-imports and returns any import/syntax error</td></tr><tr><td><code>search_interfaces(module, filters)</code></td><td>find runs by config</td></tr><tr><td><code>create_interface</code> / <code>launch</code> / <code>run_status</code></td><td>materialize / run / poll</td></tr><tr><td><code>call(interface, method, …)</code></td><td>invoke any method (the generic compute hook)</td></tr><tr><td><code>provenance(uuid, depth, rels)</code></td><td>the node-link provenance graph: recipe (config/context/derivation) plus history (executions and the code manifest each used)</td></tr></tbody></table><p><strong>Inference</strong></p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>outperforms</code> / <code>differs</code> / <code>beats_baseline</code> / <code>ranks</code> / <code>converges_faster</code></td><td>the scientific vocabulary → a verdict</td></tr><tr><td><code>infer(inference, operands, options)</code></td><td>run any catalog inference by name</td></tr><tr><td><code>quantity(operand, name)</code></td><td>probe an accessor: its value(s), or the contract naming what to write</td></tr></tbody></table><p><strong>Widget</strong>: <code>read_widget_result</code>, <code>list_widgets</code>.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong><code>guide://authoring</code></strong>: the one page that makes generated code correct. Config is always a pydantic <code>BaseModel</code>; encode axes as <code>version_*</code> methods (<code>~versions</code>); expose one run&#39;s measurement as a <code>&lt;quantity&gt;()</code>; the identity affordances (<code>Field(identifying=False)</code>, <code>predicate_from_manifest</code>).</li><li><strong><code>inferences://catalog</code></strong>: the available inferences, each with the atomic shape it requires (<code>scalar</code>/<code>series</code>) and the test it runs.</li><li><strong><code>examples://{name}</code></strong>: small, runnable, idiomatic templates: <code>interface</code>, <code>config</code>, <code>execution</code>, <code>aggregate</code>, <code>inference</code>, <code>widget</code>, and the end-to-end <code>investigate</code>.</li><li><strong><code>module://{module}</code></strong>: <em>this</em> project&#39;s resolved schema. <strong><code>widget-sdk://docs</code></strong>: the widget contract.</li></ul><h2 id="prompts" tabindex="-1">Prompts <a class="header-anchor" href="#prompts" aria-label="Permalink to &quot;Prompts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prompt</th><th>Emits</th></tr></thead><tbody><tr><td><code>investigate(hypothesis)</code></td><td>the full <a href="./workflow.html">research loop</a></td></tr><tr><td><code>scaffold-aggregate(name, axis)</code></td><td>an aggregate skeleton (grid <code>launch()</code> + a quantity stub)</td></tr><tr><td><code>add-inference(name, requires)</code></td><td>a new <code>Inference</code> subclass skeleton</td></tr><tr><td><code>scaffold-widget(name, description)</code></td><td>a <code>Widget</code> + <code>render</code> skeleton</td></tr><tr><td><code>new-interface(name)</code></td><td>a generic interface scaffold</td></tr></tbody></table><h2 id="teaching-in-the-order-an-agent-hits-it" tabindex="-1">Teaching, in the order an agent hits it <a class="header-anchor" href="#teaching-in-the-order-an-agent-hits-it" aria-label="Permalink to &quot;Teaching, in the order an agent hits it&quot;">​</a></h2><ol><li><code>guide://authoring</code>: the mental model, with each contract as a short example.</li><li><code>examples://investigate</code>: one coherent end-to-end project.</li><li>Single-concept <code>examples://{…}</code> for the contract being written.</li><li>The project&#39;s own <code>get_module</code>/<code>source</code>, since it is its own teaching material.</li><li>Runtime contracts (the <code>NotImplementedError</code>, import errors on <code>write_source</code>, schema reflection) correct the agent in context.</li></ol><p>The examples and <code>guide://authoring</code> live in <code>src/machinable/mcp/teaching/</code>.</p>',15)])])}const m=t(a,[["render",c]]);export{u as __pageData,m as default};
